// Mutation error path: server returns a typed error → inline message in the
// provenance panel, page does not crash (AC#4).
test('Regenerate error renders inline without crashing the page', async ({ page }) => {
	const state: MockState = { regenerateCalled: false, lastArtifactId: null };
	await mockRoutes(page, state);
	// Override only the mutation to return a typed error.
	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as { query: string };
		if (body.query.includes('mutation ArtifactRegenerate')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: null,
					errors: [
						{
							message: 'regeneration backend unavailable',
							extensions: { code: 'INTERNAL_ERROR' }
						}
					]
				})
			});
			return;
		}
		await route.fallback();
	});

	await page.goto(BASE_URL);
	await page.getByRole('cell', { name: 'Generated Report' }).click();
	await page.getByTestId('regenerate-button').click();
	await expect(page.getByTestId('regenerate-error')).toContainText(
		/regeneration backend unavailable/
	);
	// Page is still alive.
	await expect(page.getByRole('heading', { name: 'Generated Report' }).first()).toBeVisible();
});

import { describe, it, expect } from 'vitest';
import {
	folderOf,
	prefixOf,
	workflowStageOf,
	axisAvailable,
	groupItems,
	groupCountLabel,
	WORKFLOW_STAGE_LABEL
} from './grouping';

describe('folderOf', () => {
	it('returns parent dir for nested paths', () => {
		expect(folderOf('docs/helix/01-frame/prd.md')).toBe('docs/helix/01-frame');
	});
	it('returns "/" for top-level files', () => {
		expect(folderOf('README.md')).toBe('/');
	});
	it('handles leading slash', () => {
		expect(folderOf('/a/b/c.md')).toBe('/a/b');
	});
});

describe('prefixOf', () => {
	it('returns the first path segment', () => {
		expect(prefixOf('docs/helix/x.md')).toBe('docs');
	});
	it('strips leading slash', () => {
		expect(prefixOf('/library/personas/x.md')).toBe('library');
	});
	it('returns the whole name when there is no slash', () => {
		expect(prefixOf('README.md')).toBe('README.md');
	});
});

describe('workflowStageOf', () => {
	it('extracts a HELIX-style numbered stage segment', () => {
		expect(workflowStageOf('docs/helix/01-frame/prd.md')).toBe('frame');
		expect(workflowStageOf('docs/helix/04-build/spec.md')).toBe('build');
	});
	it('returns null when no stage segment is present', () => {
		expect(workflowStageOf('library/personas/x.md')).toBeNull();
		expect(workflowStageOf('README.md')).toBeNull();
	});
});

describe('axisAvailable', () => {
	it('is true when at least one path has a stage', () => {
		expect(axisAvailable(['README.md', 'docs/helix/02-design/x.md'])).toBe(true);
	});
	it('is false when no path has a stage', () => {
		expect(axisAvailable(['README.md', 'library/x.md'])).toBe(false);
	});
});

describe('groupItems', () => {
	const items = [
		{ path: 'docs/a.md', mediaType: 'text/markdown' },
		{ path: 'docs/b.md', mediaType: 'text/markdown' },
		{ path: 'src/x.svg', mediaType: 'image/svg+xml' }
	];
	it('groups by folder', () => {
		const groups = groupItems(items, 'folder');
		expect(groups.map((g) => g.key)).toEqual(['docs', 'src']);
		expect(groups[0].items).toHaveLength(2);
	});
	it('groups by mediaType', () => {
		const groups = groupItems(items, 'mediaType');
		expect(groups.map((g) => g.key)).toEqual(['image/svg+xml', 'text/markdown']);
	});
	it('groups by prefix', () => {
		const groups = groupItems(items, 'prefix');
		expect(groups.map((g) => g.key)).toEqual(['docs', 'src']);
	});
	it('groups by workflow stage and keeps unstaged items together', () => {
		const groups = groupItems(
			[
				{ path: 'docs/helix/01-frame/a.md', mediaType: 'text/markdown' },
				{ path: 'README.md', mediaType: 'text/markdown' }
			],
			'workflowStage'
		);
		expect(groups).toHaveLength(2);
		expect(groups.find((g) => g.key === 'frame')?.items).toHaveLength(1);
		expect(groups.find((g) => g.key === 'Unstaged')?.items).toHaveLength(1);
	});
});

describe('label constants', () => {
	it('uses generic Workflow stage label', () => {
		expect(WORKFLOW_STAGE_LABEL).toBe('Workflow stage');
	});
});

describe('groupCountLabel', () => {
	it('describes loaded pagination honestly when more pages exist', () => {
		expect(groupCountLabel(3, 12, true)).toBe('3 of 12 loaded');
	});

	it('falls back to the simple count when pagination is complete', () => {
		expect(groupCountLabel(3, 3, false)).toBe('3');
	});
});

import { defineConfig } from '@playwright/test';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

// The default Playwright harness boots the Go DDx server against a temp copy
// of e2e/fixtures/ so the API endpoints exercised by TC-008 (and other
// backend-dependent specs) return real data without reading the developer's
// $HOME or the repository's live .ddx/ state.

const CLI_PKG_DIR = path.resolve(__dirname, '../../..');
const FRONTEND_DIR = __dirname;
const FIXTURE_DIR = path.resolve(__dirname, 'e2e/fixtures');
const PORT = Number(process.env.DDX_E2E_PORT ?? 4174);
const BASE_URL = `https://127.0.0.1:${PORT}`;

// Build the SvelteKit frontend (so cli/internal/server/embed.go has assets to
// embed), copy the fixture workspace into a fresh temp dir, build the ddx
// binary from the cli module, and exec it from the temp dir. The temp dir has
// no .git so FindProjectRoot falls back to it, and tsnet is disabled so the
// harness has no Tailscale dependency.
const bootCommand = [
	`set -e`,
	`(cd "${FRONTEND_DIR}" && bun run build >&2)`,
	`TMP=$(mktemp -d -t ddx-e2e-XXXXXX)`,
	`cp -R "${FIXTURE_DIR}/." "$TMP/"`,
	`(cd "${CLI_PKG_DIR}" && go build -o "$TMP/ddx" .)`,
	`cd "$TMP"`,
	`DDX_OPERATOR_PROMPT_ALLOWLIST=localhost exec ./ddx server --tsnet=false --addr=127.0.0.1 --port=${PORT}`
].join(' && ');

export default defineConfig({
	webServer: {
		command: `bash -c '${bootCommand}'`,
		url: `${BASE_URL}/api/health`,
		ignoreHTTPSErrors: true,
		reuseExistingServer: !process.env.CI,
		timeout: 180_000,
		stdout: 'pipe',
		stderr: 'pipe'
	},
	use: {
		baseURL: BASE_URL,
		ignoreHTTPSErrors: true
	},
	testMatch: ['**/*.e2e.{ts,js}', 'e2e/**/*.spec.ts']
});

import type { PageLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'
import type { ArtifactTypeDefinition } from '$lib/artifactTypePanel'

const ARTIFACT_DETAIL_QUERY = gql`
	query ArtifactDetail($projectID: ID!, $id: ID!) {
		artifact(projectID: $projectID, id: $id) {
			id
			path
			title
			mediaType
			staleness
			description
			updatedAt
			ddxFrontmatter
			content
			typeDefinitions {
				plugin
				typeId
				name
				description
				prefix
				pattern
				phase
				sourceMetaPath
				template {
					path
					content
					isTruncated
					sizeBytes
				}
				prompt {
					path
					content
					isTruncated
					sizeBytes
				}
				examples {
					path
					description
					content
					isTruncated
					sizeBytes
				}
			}
			generatedBy {
				runId
				promptSummary
				sourceHashMatch
			}
		}
	}
`

const RUN_EXISTS_QUERY = gql`
	query RunExists($id: ID!) {
		run(id: $id) {
			id
		}
	}
`

export interface ArtifactGeneratedBy {
	runId: string
	promptSummary: string
	sourceHashMatch: boolean
}

export interface ArtifactDetail {
	id: string
	path: string
	title: string
	mediaType: string
	staleness: string
	description: string | null
	updatedAt: string | null
	ddxFrontmatter: string | null
	content: string | null
	typeDefinitions: ArtifactTypeDefinition[]
	generatedBy: ArtifactGeneratedBy | null
}

interface ArtifactDetailResult {
	artifact: ArtifactDetail | null
}

export const load: PageLoad = async ({ params, url, fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch)
	const data = await client.request<ArtifactDetailResult>(ARTIFACT_DETAIL_QUERY, {
		projectID: params.projectId,
		id: decodeURIComponent(params.artifactId)
	})

	// Build content URL for binary types (images, PDFs, unknown).
	// The UI uses this URL for <img src>, <embed src>, and download links.
	const contentUrl = data.artifact
		? `/api/projects/${encodeURIComponent(params.projectId)}/artifact-content?path=${encodeURIComponent(data.artifact.path)}`
		: null

	// Preserve back-link state so the detail page can return to the filtered list.
	const back = url.searchParams.get('back') ?? null

	// Probe whether the producing run exists, so the UI can disable the link
	// (with tooltip) when the run id is unknown.
	let runExists = false
	const gb = data.artifact?.generatedBy
	if (gb?.runId) {
		try {
			const probe = await client.request<{ run: { id: string } | null }>(RUN_EXISTS_QUERY, {
				id: gb.runId
			})
			runExists = probe.run != null
		} catch {
			runExists = false
		}
	}

	return {
		nodeId: params.nodeId,
		projectId: params.projectId,
		artifactId: params.artifactId,
		artifact: data.artifact,
		contentUrl,
		back,
		runExists
	}
}

import type { PageLoad } from './$types';
import { createClient } from '$lib/gql/client';
import { gql } from 'graphql-request';
import { readState } from '$lib/urlState';
import type { GroupBy } from './grouping';

export const ARTIFACTS_QUERY = gql`
	query Artifacts(
		$projectID: ID!
		$first: Int
		$after: String
		$mediaType: String
		$search: String
		$sort: ArtifactSort
		$staleness: String
		$phase: String
		$prefix: [String!]
	) {
		artifacts(
			projectID: $projectID
			first: $first
			after: $after
			mediaType: $mediaType
			search: $search
			sort: $sort
			staleness: $staleness
			phase: $phase
			prefix: $prefix
		) {
			edges {
				node {
					id
					path
					title
					mediaType
					staleness
				}
				cursor
				snippet
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
	}
`;

export interface ArtifactNode {
	id: string;
	path: string;
	title: string;
	mediaType: string;
	staleness: string;
}

export interface ArtifactEdge {
	node: ArtifactNode;
	cursor: string;
	snippet?: string | null;
}

export interface PageInfo {
	hasNextPage: boolean;
	endCursor: string | null;
}

export interface ArtifactConnection {
	edges: ArtifactEdge[];
	pageInfo: PageInfo;
	totalCount: number;
}

interface ArtifactsResult {
	artifacts: ArtifactConnection;
}

export const PAGE_SIZE = 50;

export const SORT_OPTIONS = [
	{ value: 'PATH', label: 'Path' },
	{ value: 'TITLE', label: 'Title' },
	{ value: 'MODIFIED', label: 'Last modified' },
	{ value: 'DEPS_COUNT', label: 'Dependency count' },
	{ value: 'ID', label: 'ID' }
] as const;

export type ArtifactSort = (typeof SORT_OPTIONS)[number]['value'];
export const DEFAULT_SORT: ArtifactSort = 'PATH';

const SORT_VALUES = new Set(SORT_OPTIONS.map((o) => o.value));

export function parseSort(raw: string | null): ArtifactSort {
	return raw && SORT_VALUES.has(raw as ArtifactSort) ? (raw as ArtifactSort) : DEFAULT_SORT;
}

export const STALENESS_OPTIONS = ['fresh', 'stale', 'missing'] as const;
export type Staleness = (typeof STALENESS_OPTIONS)[number];
const STALENESS_SET = new Set<string>(STALENESS_OPTIONS);

export function parseStaleness(raw: string | null): Staleness | null {
	return raw && STALENESS_SET.has(raw) ? (raw as Staleness) : null;
}

export const load: PageLoad = async ({ params, url, fetch }) => {
	const state = readState(url.searchParams);
	const hasGroupByParam = url.searchParams.has('groupBy');
	const mediaType = state.mediaType;
	const q = state.q;
	const groupBy: GroupBy = state.groupBy;
	const sort = parseSort(state.sort);
	const staleness = parseStaleness(state.staleness);
	const phase = state.phase;
	const prefix = state.prefix;

	const client = createClient(fetch as unknown as typeof globalThis.fetch);
	const data = await client.request<ArtifactsResult>(ARTIFACTS_QUERY, {
		projectID: params.projectId,
		first: PAGE_SIZE,
		mediaType: mediaType ?? undefined,
		search: q ? q : undefined,
		sort,
		staleness: staleness ?? undefined,
		phase: phase ?? undefined,
		prefix: prefix.length > 0 ? prefix : undefined
	});
	return {
		nodeId: params.nodeId,
		projectId: params.projectId,
		artifacts: data.artifacts,
		mediaType,
		q,
		groupBy,
		sort,
		staleness,
		phase,
		prefix,
		hasGroupByParam
	};
};

import { expect, test } from '@playwright/test';

// Seeded fixture: an artifact with known generated_by metadata (US-081b).
const NODE_INFO = { id: 'node-abc', name: 'Test Node' };
const PROJECT_ID = 'proj-1';
const PROJECTS = [{ id: PROJECT_ID, name: 'Project Alpha', path: '/repos/alpha' }];

const ARTIFACT_GENERATED = {
	id: 'artifact-generated-001',
	path: 'docs/generated/report.md',
	title: 'Generated Report',
	mediaType: 'text/markdown',
	staleness: 'fresh',
	description: 'Synthesized report',
	updatedAt: '2026-04-30T12:00:00Z',
	ddxFrontmatter: JSON.stringify({ id: 'artifact-generated-001' }),
	content: '# Generated Report\n\nBody text.\n',
	generatedBy: {
		runId: 'run-source-123',
		promptSummary: 'synthesize report from latest data',
		sourceHashMatch: true
	}
};

const ARTIFACT_PLAIN = {
	id: 'artifact-plain-001',
	path: 'docs/manual.md',
	title: 'Manual Doc',
	mediaType: 'text/markdown',
	staleness: 'fresh',
	description: null,
	updatedAt: '2026-04-30T12:00:00Z',
	ddxFrontmatter: null,
	content: '# Manual\n',
	generatedBy: null
};

const REGENERATE_RUN_ID = 'regen-artifact-generated-001-deadbeef';

const BASE_URL = `/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/artifacts`;

interface MockState {
	regenerateCalled: boolean;
	lastArtifactId: string | null;
}

async function mockRoutes(page: import('@playwright/test').Page, state: MockState) {
	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as {
			query: string;
			variables?: Record<string, string>;
		};
		const q = body.query;

		if (q.includes('NodeInfo')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
			});
			return;
		}
		if (q.includes('Projects') && !q.includes('projectID')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
				})
			});
			return;
		}
		if (q.includes('query Artifacts(') || q.includes('ArtifactsByPath')) {
			const list = [ARTIFACT_GENERATED, ARTIFACT_PLAIN];
			const search = body.variables?.search;
			const filtered = search
				? list.filter(
						(a) =>
							a.title.toLowerCase().includes(String(search).toLowerCase()) ||
							a.path.toLowerCase().includes(String(search).toLowerCase())
					)
				: list;
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						artifacts: {
							edges: filtered.map((a, i) => ({
								node: {
									id: a.id,
									path: a.path,
									title: a.title,
									mediaType: a.mediaType,
									staleness: a.staleness
								},
								cursor: `c${i}`
							})),
							pageInfo: { hasNextPage: false, endCursor: null },
							totalCount: filtered.length
						}
					}
				})
			});
			return;
		}
		if (q.includes('ArtifactDetail')) {
			const id = body.variables?.id;
			const match = [ARTIFACT_GENERATED, ARTIFACT_PLAIN].find((a) => a.id === id);
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { artifact: match ?? null } })
			});
			return;
		}
		if (q.includes('RunExists')) {
			const id = body.variables?.id;
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: { run: id === ARTIFACT_GENERATED.generatedBy.runId ? { id } : null }
				})
			});
			return;
		}
		if (q.includes('mutation ArtifactRegenerate')) {
			state.regenerateCalled = true;
			state.lastArtifactId = body.variables?.artifactId ?? null;
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {
						artifactRegenerate: { runId: REGENERATE_RUN_ID, status: 'queued' }
					}
				})
			});
			return;
		}
		if (q.includes('Run(') || q.includes('query Run')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { run: { id: REGENERATE_RUN_ID } } })
			});
			return;
		}
		await route.continue();
	});
}

// Full US-081b workflow: list → filter → open → renderer → provenance →
// Regenerate → run id shown → follow run link → navigate back to artifact.
test('US-081b end-to-end: list → filter → open → regenerate → run link → back', async ({
	page
}) => {
	const state: MockState = { regenerateCalled: false, lastArtifactId: null };
	await mockRoutes(page, state);

	// 1. List
	await page.goto(BASE_URL);
	await expect(page.getByText('Generated Report')).toBeVisible();
	await expect(page.getByText('Manual Doc')).toBeVisible();

	// 2. Filter (search) — narrow to the generated artifact via path/title.
	const search = page.getByPlaceholder(/Search/i).first();
	await search.fill('Generated');
	await expect(page.getByText('Generated Report')).toBeVisible();

	// 3. Open
	await page.getByRole('cell', { name: 'Generated Report' }).click();
	await expect(page).toHaveURL(new RegExp(`/artifacts/${ARTIFACT_GENERATED.id}`));

	// 4. Verify renderer (markdown body shown). The page renders the artifact
	//    title as <h1> and the markdown body also renders <h1># Generated
	//    Report</h1>, so we use .first() to disambiguate without weakening the
	//    visibility assertion.
	await expect(page.getByRole('heading', { name: 'Generated Report' }).first()).toBeVisible();
	await expect(page.getByText(/Body text\./)).toBeVisible();

	// 5. Provenance panel visible.
	await expect(page.getByTestId('provenance-panel')).toBeVisible();

	// 6. Click Regenerate.
	await page.getByTestId('regenerate-button').click();

	// 7. Verify run id shown + dispatched mutation called.
	const runLink = page.getByTestId('regenerate-run-link');
	await expect(runLink).toBeVisible();
	await expect(runLink).toHaveText(REGENERATE_RUN_ID);
	expect(state.regenerateCalled).toBe(true);
	expect(state.lastArtifactId).toBe(ARTIFACT_GENERATED.id);

	// 8. Follow run link.
